---
import type { ImageMetadata } from "astro"
import { Image } from "astro:assets"

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  badge?: string
  title: string
  description?: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  services: {
    image: {
      src: ImageMetadata
      alt: string
    }
    title: string
    description: string
    button?: {
      label: string
      href: string
    }
  }[]
}

const {
  class: className,
  badge,
  title,
  description,
  buttons,
  services,
} = Astro.props
---

<Section class={cn("", className)}>
  <SectionContainer class="gap-8">
    <div class="mx-auto max-w-2xl text-center">
      {badge && <Badge variant="secondary">{badge}</Badge>}
      <h2
        class="mt-4 text-3xl font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      {
        description && (
          <p class="text-muted-foreground mt-4 text-base leading-relaxed text-balance">
            {description}
          </p>
        )
      }
      {
        buttons?.length && (
          <div class="mt-6 flex flex-wrap justify-center gap-3">
            {buttons.map(({ href, label, ...button }) => (
              <Button as="a" href={href} variant={button.variant}>
                {label}
              </Button>
            ))}
          </div>
        )
      }
    </div>
    <div class="grid gap-6 sm:grid-cols-2">
      {
        services.map((service) => (
          <div class="group/service relative isolate flex aspect-4/3 flex-col justify-end overflow-hidden rounded-xl">
            <Image
              src={service.image.src}
              alt={service.image.alt}
              class="absolute inset-0 -z-10 size-full object-cover transition-transform duration-500 group-hover/service:scale-105"
              widths={[480, 640, 960]}
              sizes="(min-width: 640px) 50vw, 100vw"
            />
            <div class="absolute inset-0 -z-10 bg-linear-to-t from-black/80 via-black/40 to-transparent" />
            <div class="flex flex-col gap-2 p-6 text-white">
              <h3 class="text-xl font-semibold">{service.title}</h3>
              <p class="text-sm leading-relaxed text-white/80">
                {service.description}
              </p>
              {service.button && (
                <Button
                  as="a"
                  href={service.button.href}
                  variant="secondary"
                  class="mt-2 w-fit"
                >
                  {service.button.label}
                </Button>
              )}
            </div>
          </div>
        ))
      }
    </div>
  </SectionContainer>
</Section>
